def _sapbw_transformation_from_nested(
    nested: SAPBWTransformationNested,
) -> SAPBWTransformation:
    """Convert nested format to flat SAPBWTransformation."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else SAPBWTransformationAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _SAPBW_TRANSFORMATION_REL_FIELDS,
        SAPBWTransformationRelationshipAttributes,
    )
    return SAPBWTransformation(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_sapbw_transformation_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _sapbw_transformation_to_nested_bytes(
    sapbw_transformation: SAPBWTransformation, serde: Serde
) -> bytes:
    """Convert flat SAPBWTransformation to nested JSON bytes."""
    return serde.encode(_sapbw_transformation_to_nested(sapbw_transformation))


def _sapbw_transformation_from_nested_bytes(
    data: bytes, serde: Serde
) -> SAPBWTransformation:
    """Convert nested JSON bytes to flat SAPBWTransformation."""
    nested = serde.decode(data, SAPBWTransformationNested)
    return _sapbw_transformation_from_nested(nested)


